/**
 * Organization Module Definition
 *
 * Core organization/tenant management module for E-Menum.
 * Provides multi-tenant support, organization CRUD, and settings management.
 *
 * This is a CORE module - it cannot be disabled.
 *
 * @module modules/_core/organization/organization.module
 *
 * @example
 * ```typescript
 * import { OrganizationModule } from '@/modules/_core/organization/organization.module';
 *
 * // Module is automatically discovered and loaded by ModuleLoader
 * // Access module instance via DI container
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
import type { ModuleInstance } from '@/core/kernel/module-loader';
import type { EventService } from '@/core/services/event.service';

import { OrganizationController } from '@/modules/_core/organization/organization.controller';
import { OrganizationService } from '@/modules/_core/organization/organization.service';
import { OrganizationRepository } from '@/modules/_core/organization/organization.repository';
import { organizationRoutes } from '@/modules/_core/organization/organization.routes';
import type { OrganizationModuleSettings } from '@/modules/_core/organization/organization.types';

// -----------------------------------------------------------------------------
// Module Types
// -----------------------------------------------------------------------------

/**
 * Organization module context for lifecycle hooks
 */
export interface OrganizationModuleContext {
  /** Event service for pub/sub */
  events: EventService;
  /** Module settings */
  settings: OrganizationModuleSettings;
  /** Logger function */
  log: (message: string) => void;
}

/**
 * Organization module hook definitions
 */
export interface OrganizationModuleHooks {
  /** Called before organization creation */
  beforeCreate?: (data: { name: string; email: string }) => Promise<void>;
  /** Called after organization creation */
  afterCreate?: (data: { organizationId: string }) => Promise<void>;
  /** Called before organization update */
  beforeUpdate?: (data: { organizationId: string }) => Promise<void>;
  /** Called after organization update */
  afterUpdate?: (data: { organizationId: string }) => Promise<void>;
  /** Called before organization deletion */
  beforeDelete?: (data: { organizationId: string }) => Promise<void>;
  /** Called after organization deletion */
  afterDelete?: (data: { organizationId: string }) => Promise<void>;
}

// -----------------------------------------------------------------------------
// Organization Module Class
// -----------------------------------------------------------------------------

/**
 * Organization Module
 *
 * Core module providing organization/tenant management for E-Menum.
 * Handles multi-tenant data isolation, organization CRUD, and settings.
 *
 * Features:
 * - Organization CRUD operations
 * - Settings management (business, localization, features, etc.)
 * - Status management (active, inactive, suspended)
 * - Slug and email validation
 * - Soft delete with restore capability
 *
 * @example
 * ```typescript
 * // Module is automatically loaded by ModuleLoader
 * // Use OrganizationService for business logic
 * const orgService = container.resolve('OrganizationService');
 * await orgService.create({ name: 'My Restaurant', email: 'contact@example.com' });
 * ```
 */
@injectable()
export class OrganizationModule implements ModuleInstance {
  // ---------------------------------------------------------------------------
  // Static Properties
  // ---------------------------------------------------------------------------

  /** Module ID */
  static readonly id = 'organization';

  /** Module name */
  static readonly name = 'Organization Module';

  /** Module version */
  static readonly version = '1.0.0';

  /** Is core module (cannot be disabled) */
  static readonly isCore = true;

  /** Module routes configuration */
  static readonly routes = organizationRoutes;

  /** Providers (services) to register */
  static readonly providers = [OrganizationService, OrganizationRepository];

  /** Controllers to register */
  static readonly controllers = [OrganizationController];

  // ---------------------------------------------------------------------------
  // Instance Properties
  // ---------------------------------------------------------------------------

  /** Module hooks registry */
  private hooks: OrganizationModuleHooks = {};

  /** Module initialized flag */
  private initialized = false;

  constructor(
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // ModuleInstance Lifecycle Hooks
  // ---------------------------------------------------------------------------

  /**
   * Called when module is loaded.
   * Registers services with DI container.
   */
  async onLoad(): Promise<void> {
    this.log('Loading organization module...');

    // Register OrganizationRepository with DI container
    if (!appContainer.isRegistered('OrganizationRepository')) {
      registerSingleton('OrganizationRepository', OrganizationRepository);
    }

    // Register OrganizationService with DI container
    if (!appContainer.isRegistered('OrganizationService')) {
      registerSingleton('OrganizationService', OrganizationService);
    }

    this.log('Organization module loaded');
  }

  /**
   * Called when module is enabled/activated.
   * Sets up event listeners and registers routes.
   */
  async onEnable(): Promise<void> {
    if (this.initialized) {
      this.log('Organization module already initialized');
      return;
    }

    this.log('Enabling organization module...');

    // Subscribe to relevant events
    this.setupEventListeners();

    this.initialized = true;
    this.log('Organization module enabled');

    // Emit module activated event
    await this.eventService.emitCustom('module.activated', {
      moduleId: OrganizationModule.id,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Called when module is disabled/deactivated.
   * Core modules cannot be fully disabled, but this handles graceful pause.
   */
  async onDisable(): Promise<void> {
    this.log('Organization module disable requested (core module - limited action)');

    // Core modules cannot be fully disabled
    // This would only be called during shutdown

    this.initialized = false;
    this.log('Organization module disabled');
  }

  /**
   * Called when module is unloaded.
   * Cleans up resources.
   */
  async onUnload(): Promise<void> {
    this.log('Unloading organization module...');

    // Clear hooks
    this.hooks = {};

    this.log('Organization module unloaded');
  }

  // ---------------------------------------------------------------------------
  // ModuleInstance Interface Methods
  // ---------------------------------------------------------------------------

  /**
   * Returns module routes for registration with Express.
   *
   * @returns Route configuration array
   */
  getRoutes(): unknown[] {
    return [organizationRoutes];
  }

  /**
   * Returns module controllers for registration with routing-controllers.
   *
   * @returns Controller class array
   */
  getControllers(): unknown[] {
    return OrganizationModule.controllers;
  }

  // ---------------------------------------------------------------------------
  // Hook System
  // ---------------------------------------------------------------------------

  /**
   * Gets current module hooks.
   *
   * @returns Module hooks object
   */
  getHooks(): OrganizationModuleHooks {
    return { ...this.hooks };
  }

  /**
   * Registers a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handler - Hook handler function
   *
   * @example
   * ```typescript
   * orgModule.registerHook('afterCreate', async (data) => {
   *   console.log('Organization created:', data.organizationId);
   * });
   * ```
   */
  registerHook<K extends keyof OrganizationModuleHooks>(
    hookName: K,
    handler: OrganizationModuleHooks[K]
  ): void {
    this.hooks[hookName] = handler;
    this.log(`Registered hook: ${hookName}`);
  }

  /**
   * Unregisters a hook handler.
   *
   * @param hookName - Name of the hook to unregister
   */
  unregisterHook(hookName: keyof OrganizationModuleHooks): void {
    delete this.hooks[hookName];
    this.log(`Unregistered hook: ${hookName}`);
  }

  /**
   * Executes a hook if registered.
   *
   * @param hookName - Name of the hook
   * @param data - Data to pass to the hook
   */
  async executeHook<K extends keyof OrganizationModuleHooks>(
    hookName: K,
    data: Parameters<NonNullable<OrganizationModuleHooks[K]>>[0]
  ): Promise<void> {
    const hook = this.hooks[hookName];
    if (hook) {
      try {
        await (hook as (data: typeof data) => Promise<void>)(data);
      } catch (error) {
        this.log(`Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`);
      }
    }
  }

  // ---------------------------------------------------------------------------
  // Event Listeners
  // ---------------------------------------------------------------------------

  /**
   * Sets up event listeners for the organization module.
   */
  private setupEventListeners(): void {
    // Listen for subscription changes that affect organization status
    this.eventService.on('subscription.expired', async (payload) => {
      this.log(`Subscription expired event received: ${payload.organizationId}`);
      // Could trigger status change to INACTIVE
    });

    // Listen for plan changes
    this.eventService.on('subscription.plan.changed', async (payload) => {
      this.log(`Plan changed event received: ${payload.organizationId}`);
      // Could update organization settings based on new plan
    });

    this.log('Event listeners set up');
  }

  // ---------------------------------------------------------------------------
  // Module Settings
  // ---------------------------------------------------------------------------

  /**
   * Gets default module settings.
   *
   * @returns Default organization module settings
   */
  static getDefaultSettings(): OrganizationModuleSettings {
    return {
      defaultTimezone: 'Europe/Istanbul',
      defaultCurrency: 'TRY',
      defaultLanguage: 'tr',
      allowPublicRegistration: false,
      requireEmailVerification: true,
      maxUsersPerOrg: 50,
      maxBranchesPerOrg: 10,
    };
  }

  // ---------------------------------------------------------------------------
  // Utility Methods
  // ---------------------------------------------------------------------------

  /**
   * Logs a message with module prefix.
   *
   * @param message - Message to log
   */
  private log(message: string): void {
    // eslint-disable-next-line no-console
    console.log(`[OrganizationModule] ${message}`);
  }

  /**
   * Checks if module is initialized.
   *
   * @returns True if module is initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Gets module metadata.
   *
   * @returns Module metadata object
   */
  static getMetadata() {
    return {
      id: OrganizationModule.id,
      name: OrganizationModule.name,
      version: OrganizationModule.version,
      isCore: OrganizationModule.isCore,
      routes: OrganizationModule.routes,
      providers: OrganizationModule.providers.map((p) => p.name),
      controllers: OrganizationModule.controllers.map((c) => c.name),
    };
  }
}

// -----------------------------------------------------------------------------
// Module Exports
// -----------------------------------------------------------------------------

/**
 * Default export for module loader dynamic import
 */
export default OrganizationModule;

/**
 * Export module metadata
 */
export const metadata = OrganizationModule.getMetadata();
